// ─── Payroll Sync Panel (LV-044) ─────────────────────────────────────────────
function PayrollSyncPanel({ onSync }) {
  const [syncing, setSyncing] = useState(false);
  const [lastSync, setLastSync] = useState(null);

  const handlePayrollSync = async () => {
    setSyncing(true);
    try {
      await onSync();
      setLastSync(new Date().toLocaleString());
    } finally { 
      setSyncing(false); 
    }
  };

  return (
    <div style={{ padding: '12px 16px', background: 'var(--surface-alt,#1e1e2e)', borderRadius: 'var(--radius-md)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
      <div>
        <div style={{ fontWeight: 600, fontSize: '0.875rem', display: 'flex', alignItems: 'center', gap: 6 }}>
          <ArrowRightLeft size={14} />Payroll Sync
        </div>
        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: 2 }}>
          {lastSync ? `Last synced: ${lastSync}` : 'Not yet synced this session'}
        </div>
      </div>
      <button className="btn btn-primary btn-sm" onClick={handlePayrollSync} disabled={syncing}>
        {syncing ? <InlineSpinner /> : <><RefreshCw size={13} style={{ marginRight: 4 }} />Sync Now</>}
      </button>
    </div>
  );
}

// ─── Delegation Panel (LV-023) ───────────────────────────────────────────────
function DelegationPanel() {
  const [delegateTo, setDelegateTo] = useState('');
  const [until, setUntil] = useState('');
  const [active, setActive] = useState(false);

  return (
    <div className="card" style={{ marginBottom: 16 }}>
      <div className="card-header">
        <div className="card-title"><Users size={15} style={{ marginRight: 6 }} />Approval Delegation</div>
        {active && <span className="badge" style={{ background: 'rgba(34,197,94,0.15)', color: '#16a34a', fontSize: '0.72rem' }}>Active</span>}
      </div>
      <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: 12 }}>
        Delegate your approval authority to another manager while you're away.
      </p>
      <div className="form-row">
        <div className="form-group">
          <label className="form-label">Delegate To (Employee ID)</label>
          <input className="form-input" type="text" value={delegateTo} onChange={e => setDelegateTo(e.target.value)} placeholder="e.g. EMP-1042" />
        </div>
        <div className="form-group">
          <label className="form-label">Delegate Until</label>
          <input className="form-input" type="date" value={until} onChange={e => setUntil(e.target.value)} />
        </div>
      </div>
      <div style={{ display: 'flex', gap: 8 }}>
        <button className="btn btn-primary btn-sm" disabled={!delegateTo || !until}
          onClick={() => { setActive(true); toast.success(`Delegation active until ${until}`); }}>
          Activate Delegation
        </button>
        {active && (
          <button className="btn btn-ghost btn-sm" onClick={() => { setActive(false); toast.success('Delegation revoked'); }}>
            Revoke
          </button>
