}

// ─── HR Manager Override Panel (LV-026) ──────────────────────────────────────
function OverridePanel({ requests, onOverride }) {
  const [selected, setSelected] = useState('');
  const [newStatus, setNewStatus] = useState('APPROVED');
  const [reason, setReason] = useState('');

  return (
    <div className="card" style={{ marginBottom: 16 }}>
      <div className="card-header">
        <div className="card-title"><Shield size={15} style={{ marginRight: 6 }} />Override Manager Decision</div>
      </div>
      <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: 12 }}>
        HR Manager can override any approved or rejected decision. This action is logged.
      </p>
      <div className="form-group">
        <label className="form-label">Select Request</label>
        <select className="form-select" value={selected} onChange={e => setSelected(e.target.value)}>
          <option value="">— Select a request —</option>
          {requests.filter(r => isFinalStatus(r.Status || r.status)).map(r => {
            const id = r.LeaveRequestID || r.leaveRequestId || r.id;
            const emp = r.employeeName || r.Employee?.FullName || id;
            const type = r.leaveTypeName || r.LeaveTypeName || '';
            return <option key={id} value={id}>{emp} — {type} ({r.Status || r.status})</option>;
          })}
        </select>
      </div>
      <div className="form-row">
        <div className="form-group">
          <label className="form-label">Override To</label>
          <select className="form-select" value={newStatus} onChange={e => setNewStatus(e.target.value)}>
            <option value="APPROVED">Approved</option>
            <option value="REJECTED">Rejected</option>
          </select>
        </div>
      </div>
      <div className="form-group">
        <label className="form-label required">Override Reason</label>
        <textarea className="form-textarea" rows={2} value={reason} onChange={e => setReason(e.target.value)} placeholder="Provide justification for override…" />
      </div>
      <button className="btn btn-primary btn-sm" disabled={!selected || !reason.trim()}
        onClick={() => { onOverride(selected, newStatus, reason); setSelected(''); setReason(''); }}>
        Apply Override
      </button>
    </div>
  );
}

// ─── Adjust Balance Modal (LV-013) ───────────────────────────────────────────
function AdjustBalanceModal({ onClose }) {
  const [form, setForm] = useState({ EmployeeID: '', LeaveTypeID: '', BalanceYear: new Date().getFullYear(), AdjustedDays: '', Reason: '' });
  const handleSubmit = async () => {
    if (!form.EmployeeID || !form.LeaveTypeID || !form.AdjustedDays) {
      return toast.error('Please fill Employee ID, Leave Type ID, and Days');
    }
    try {
      await leaveAPI.adjustBalance(form);
      toast.success('Balance adjusted successfully!');
      onClose();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to adjust balance'); }
  };
  return (
    <Modal title="Adjust Employee Leave Balance" onClose={onClose}>
      <div className="space-y-4">
        <input type="number" placeholder="Employee ID" className="form-input" onChange={e => setForm(f => ({ ...f, EmployeeID: e.target.value }))} />
        <input type="number" placeholder="Leave Type ID" className="form-input" onChange={e => setForm(f => ({ ...f, LeaveTypeID: e.target.value }))} />
        <input type="number" placeholder="Year" className="form-input" value={form.BalanceYear} onChange={e => setForm(f => ({ ...f, BalanceYear: e.target.value }))} />
        <input type="number" placeholder="Days to Adjust (±)" className="form-input" onChange={e => setForm(f => ({ ...f, AdjustedDays: e.target.value }))} />
        <textarea placeholder="Reason for adjustment (optional)" className="form-textarea" onChange={e => setForm(f => ({ ...f, Reason: e.target.value }))} />
        <button className="btn btn-primary w-full" onClick={handleSubmit}>Apply Adjustment</button>
      </div>
    </Modal>
  );
}


// ─── MAIN LEAVE PAGE COMPONENT ───────────────────────────────────────────────

export default function LeavePage() {
  const { user } = useAuth();

  // ROLE-BASED TAB LOGIC
  const isManager = ['Manager', 'HR Manager', 'System Admin'].includes(user?.role);
  const isHR = ['HR Manager', 'System Admin'].includes(user?.role);

  const [tab, setTab] = useState('history');

  // Data State
  const [myRequests, setMyRequests] = useState([]);
  const [teamRequests, setTeamRequests] = useState([]); // Manager Inbox
  const [allRequests, setAllRequests] = useState([]);   // HR View
  const [balances, setBalances] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [leaveTypes, setLeaveTypes] = useState([]);

  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);
  const [filterStatus, setFilterStatus] = useState('');

  // Modals state
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);
  const [isAdjustBalanceModalOpen, setIsAdjustBalanceModalOpen] = useState(false);
  const [editingRequest, setEditingRequest] = useState(null);

  // ─── DATA LOADING SYNC ─────────────────────────────────────────────────────

  const loadDashboardData = useCallback(async () => {
    setLoading(true);
    try {
      // 1. Core Employee Data (Everyone needs this)
      const [myReqRes, balRes, notifRes, typeRes] = await Promise.all([
        leaveAPI.getMyRequests({ status: filterStatus }),
        leaveAPI.getMyBalances(),
        notificationAPI.getNotifications(),
        leaveAPI.getTypes ? leaveAPI.getTypes() : Promise.resolve({ data: [] })
      ]);

      setMyRequests(myReqRes.data || []);
      setBalances(balRes.data || []);
      setNotifications(notifRes.data || []);
      setLeaveTypes(typeRes.data || balRes.data.map(b => b.LeaveType || b.leaveType).filter(Boolean));

      // 2. Manager Sync
      if (isManager) {
        const inboxRes = await leaveAPI.getManagerInbox();
        setTeamRequests(inboxRes.data || []);
      }

      // 3. HR Sync
      if (isHR) {
        const allRes = await leaveAPI.listAll({ status: filterStatus });
        // Assuming API returns { data: { requests: [...] } } or { data: [...] }
        setAllRequests(allRes.data?.requests || allRes.data || []);
      }

    } catch (err) {
      toast.error("Failed to sync with HR records");
    } finally {
      setLoading(false);
    }
  }, [filterStatus, isManager, isHR]);

  useEffect(() => {
    loadDashboardData();
  }, [loadDashboardData]);

  // ─── HANDLERS ─────────────────────────────────────────────────────────────

  const handleUpdateLeave = async (updatedData) => {
    setActionLoading(true);
    try {
      await leaveAPI.updateRequest(editingRequest.LeaveRequestID || editingRequest.id, updatedData);
      toast.success("Request modified successfully");
      setEditingRequest(null);
      await loadDashboardData();
    } catch (err) { toast.error(err.response?.data?.message || "Modification failed"); } 
    finally { setActionLoading(false); }
  };

  const handleCancelRequest = async (id) => {
    const reason = window.prompt("Reason for cancellation:");
    if (!reason) return;
    setActionLoading(true);
    try {
      await leaveAPI.cancelRequest(id, { cancelReason: reason });
      toast.success("Leave request cancelled");
      await loadDashboardData();
    } catch (err) { toast.error(err.response?.data?.message || "Cancellation failed"); } 
    finally { setActionLoading(false); }
  };

  const handleSubmitLeave = async (formData) => {
    setActionLoading(true);
    try {
      await leaveAPI.submitRequest(formData);
      toast.success("Leave request submitted successfully");
      setIsSubmitModalOpen(false);
      await loadDashboardData();
    } catch (err) { toast.error(err.response?.data?.message || "Failed to submit request"); } 
    finally { setActionLoading(false); }
  };

  const handleOverrideDecision = async (requestId, newStatus, reason) => {
    setActionLoading(true);
    try {
      await leaveAPI.approveReject(requestId, { decision: newStatus, comments: reason, isOverride: true });
      toast.success(`Request overridden to ${newStatus}`);
      await loadDashboardData();
    } catch (err) { toast.error(err.response?.data?.message || "Override failed"); } 
    finally { setActionLoading(false); }
  };

  const handleSyncToPayroll = async () => {
    const period = { periodYear: new Date().getFullYear(), periodMonth: new Date().getMonth() + 1 };
    const response = await leaveAPI.syncPayroll(period);
    toast.success(`Synced ${response.data?.syncedCount || 0} leave records to payroll`);
  };

  const handleManagerAction = async (id, action) => {
    setActionLoading(true);
    try {
      await leaveAPI.approveReject(id, { decision: action.toUpperCase(), comments: 'Processed via Dashboard' });
      toast.success(`Request ${action}d successfully`);
      await loadDashboardData();
    } catch (err) { toast.error(err.response?.data?.message || `Failed to ${action} request`); } 
    finally { setActionLoading(false); }
  };

  // ─── UI Rendering ──────────────────────────────────────────────────────────

  if (loading && myRequests.length === 0 && balances.length === 0) return <SkeletonCard count={4} />;

  // Define allowed tabs based on role
  const availableTabs = [
    { id: 'history', label: 'My Leave History' },
    ...(isManager ? [
      { id: 'team', label: 'Team Approval Inbox' },
      { id: 'delegation', label: 'Delegation' }
    ] : []),
    ...(isHR ? [
      { id: 'hr-dashboard', label: 'Company Overview' },
      { id: 'settings', label: 'HR Admin Settings' }
    ] : [])
  ];

  return (
    <div className="leave-module" style={{ padding: '2rem' }}>

      {/* Module Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <div>
          <h1 style={{ fontSize: '1.875rem', fontWeight: 700, color: 'var(--text-primary)' }}>Leave Management</h1>
          <p style={{ color: 'var(--text-secondary)' }}>Track balances, submit requests, and manage approvals.</p>
        </div>
        <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
          <NotificationBell notifications={notifications} onMarkRead={() => setNotifications(n => n.map(x => ({ ...x, read: true })))} />
          <button className="btn btn-primary" onClick={() => setIsSubmitModalOpen(true)}>
            <Plus size={18} style={{ marginRight: 8 }} /> New Request
          </button>
        </div>
      </div>

      {/* Everyone sees their own balances */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1.5rem', marginBottom: '2.5rem' }}>
        {balances.map((bal) => (
          <BalanceCard key={bal.BalanceID || bal.LeaveTypeID} balance={bal} loading={loading} />
        ))}
      </div>

      {/* RBAC TABS */}
      <div className="tabs" style={{ display: 'flex', gap: '2rem', borderBottom: '1px solid var(--border-color)', marginBottom: '1.5rem' }}>
        {availableTabs.map((t) => (
          <button
            key={t.id}
            onClick={() => setTab(t.id)}
            className={`tab-item ${tab === t.id ? 'active' : ''}`}
            style={{ 
              paddingBottom: '1rem', 
              fontWeight: tab === t.id ? 600 : 400,
              background: 'none', border: 'none',
              borderBottom: tab === t.id ? '2px solid var(--primary)' : 'none',
              cursor: 'pointer',
              color: tab === t.id ? 'var(--primary)' : 'var(--text-secondary)'
            }}
          >
            {t.label}
          </button>
        ))}
      </div>

      {/* CONTENT PANELS */}
      <div className="tab-content">

        {/* EMPLOYEE VIEW - My History */}
        {tab === 'history' && (
          <div className="card shadow-sm">
            <div className="p-4" style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid var(--border-light)', paddingBottom: '1rem', marginBottom: '1rem' }}>
              <h3 style={{ fontWeight: 600, fontSize: '1.1rem' }}>My Leave History</h3>
              <div style={{ display: 'flex', gap: '10px' }}>
                 <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="form-select" style={{ padding: '4px 8px', fontSize: '0.875rem' }}>
                   {STATUS_OPTIONS.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                 </select>
                 <button onClick={loadDashboardData} className="btn btn-ghost btn-sm" style={{ padding: '6px' }}><RefreshCw size={16} /></button>
              </div>
            </div>
            <table className="table" style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
              <thead>
                <tr style={{ textAlign: 'left', borderBottom: '1px solid var(--border)', color: 'var(--text-muted)' }}>
                  <th style={{ padding: '12px 8px' }}>Type & Details</th><th style={{ padding: '12px 8px' }}>Dates</th>
                  <th style={{ padding: '12px 8px' }}>Duration</th><th style={{ padding: '12px 8px' }}>Status</th><th style={{ padding: '12px 8px' }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {myRequests.filter(req => statusMatches(req.Status || req.status, filterStatus)).map((req) => (
                  <RequestRow key={req.LeaveRequestID || req.id} req={req} onAction={handleManagerAction} onEdit={() => setEditingRequest(req)} isManager={false} userRole={user?.role} />
                ))}
              </tbody>
            </table>
          </div>
        )}

        {/* MANAGER VIEW - Inbox & Team */}
        {tab === 'team' && isManager && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <div className="card shadow-sm">
              <div className="p-4"><h3 style={{ fontWeight: 600, fontSize: '1.1rem', marginBottom: '1rem' }}>Pending Team Approvals</h3></div>
              <table className="table" style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
                <thead>
                  <tr style={{ textAlign: 'left', borderBottom: '1px solid var(--border)', color: 'var(--text-muted)' }}>
                    <th style={{ padding: '12px 8px' }}>Request Details</th><th style={{ padding: '12px 8px' }}>Employee</th>
                    <th style={{ padding: '12px 8px' }}>Dates</th><th style={{ padding: '12px 8px' }}>Days</th>
                    <th style={{ padding: '12px 8px' }}>Status</th><th style={{ padding: '12px 8px' }}>Reason</th>
                    <th style={{ padding: '12px 8px' }}>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {teamRequests.map((req) => (
                    <RequestRow key={req.LeaveRequestID || req.id} req={req} onAction={handleManagerAction} isManager={true} userRole={user?.role} />
                  ))}
                </tbody>
              </table>
              {teamRequests.length === 0 && <div style={{ padding: '2rem', textAlign: 'center' }}><EmptyState message="No pending approvals." /></div>}
            </div>
            <TeamLeaveCalendar teamLeaves={isHR ? allRequests : teamRequests} />
            <LeavePatternAlerts requests={isHR ? allRequests : teamRequests} />
          </div>
        )}

        {tab === 'delegation' && isManager && (
           <div className="card shadow-sm" style={{ padding: '1.5rem' }}>
             <DelegationPanel />
           </div>
        )}

        {/* HR MANAGER VIEW - Company Overview & Settings */}
        {tab === 'hr-dashboard' && isHR && (
           <div className="card shadow-sm">
            <div className="p-4" style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid var(--border-light)', paddingBottom: '1rem', marginBottom: '1rem' }}>
              <h3 style={{ fontWeight: 600, fontSize: '1.1rem' }}>Company-Wide Leave Requests</h3>
            </div>
            <table className="table" style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
              <thead>
                <tr style={{ textAlign: 'left', borderBottom: '1px solid var(--border)', color: 'var(--text-muted)' }}>
                  <th style={{ padding: '12px 8px' }}>Request Details</th><th style={{ padding: '12px 8px' }}>Employee</th>
                  <th style={{ padding: '12px 8px' }}>Dates</th><th style={{ padding: '12px 8px' }}>Days</th>
                  <th style={{ padding: '12px 8px' }}>Status</th><th style={{ padding: '12px 8px' }}>Reason</th>
                  <th style={{ padding: '12px 8px' }}>Override</th>
                </tr>
              </thead>
              <tbody>
                {allRequests.filter(req => statusMatches(req.Status || req.status, filterStatus)).map((req) => (
                  <RequestRow key={req.LeaveRequestID || req.id} req={req} onAction={handleManagerAction} isManager={true} userRole={user?.role} />
                ))}
              </tbody>
            </table>
          </div>
        )}

        {tab === 'settings' && isHR && (
          <div className="settings-grid" style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '1.5rem' }}>
            <PayrollSyncPanel onSync={handleSyncToPayroll} />
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: '1.5rem' }}>
              <AccrualPanel onSaveSettings={() => {}} />
              <OverridePanel requests={allRequests} onOverride={handleOverrideDecision} />

              <div className="card" style={{ padding: '1.5rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '1rem', fontWeight: 600 }}>
                  <ArrowRightLeft size={16} /> Balance Adjustments
                </div>
                <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: '1rem' }}>Manually adjust an employee's leave balance in the database.</p>
                <button className="btn btn-primary btn-sm" onClick={() => setIsAdjustBalanceModalOpen(true)}>Perform Manual Adjustment</button>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Modals */}
      {isSubmitModalOpen && (
        <Modal title="Submit Leave Request" onClose={() => setIsSubmitModalOpen(false)}>
          <SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={handleSubmitLeave} loading={actionLoading} />
        </Modal>
      )}

      {editingRequest && (
        <EditRequestModal req={editingRequest} leaveTypes={leaveTypes} onSave={handleUpdateLeave} onClose={() => setEditingRequest(null)} loading={actionLoading} />
      )}

      {isAdjustBalanceModalOpen && isHR && (
        <AdjustBalanceModal onClose={() => { setIsAdjustBalanceModalOpen(false); loadDashboardData(); }} />
      )}

      {actionLoading && (
        <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 9999 }}>
          <div style={{ background: 'var(--surface)', padding: '2rem', borderRadius: 'var(--radius-lg)', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem' }}>
            <InlineSpinner />
            <span style={{ fontWeight: 500 }}>Processing system workflow...</span>
          </div>
        </div>
      )}
    </div>
  );
}
